parameters.new_string:
  it('should paginate with large page size', () => {
    const result = paginate(items, 1, 100);
    expect(result.items).toEqual(items);
    expect(result.totalPages).toBe(1);
  });

  it('should not produce duplicate items between consecutive pages', () => {
    // Regression: offset was (page-1)*pageSize - 1 for page > 1,
    // causing the last item of page N to reappear on page N+1.
    const page1 = paginate(items, 1, 3);
    const page2 = paginate(items, 2, 3);
    const page3 = paginate(items, 3, 3);
    const page4 = paginate(items, 4, 3);

    expect(page1.items).toEqual([1, 2, 3]);
    expect(page2.items).toEqual([4, 5, 6]);
    expect(page3.items).toEqual([7, 8, 9]);
    expect(page4.items).toEqual([10]);

    // All items across all pages should be unique and cover the full set
    const allItems = [...page1.items, ...page2.items, ...page3.items, ...page4.items];
    expect(allItems).toEqual(items);
  });
});

